82	export interface ClaimResult {
83	  payout: number;
84	}
85	
86	const DEDUCTIBLE = 100;
87	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
88	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
89	
90	export function claim(input: ClaimInput): ClaimResult {
91	  const payout = input.damages.reduce(
92	    (sum, damage) => {
93	      const policyItem = input.policyItems.find((item) => item.type === damage.type);
94	      let reimbursement = damage.amount;
95	      if (policyItem && policyItem.enchantment !== undefined && policyItem.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
96	        reimbursement = damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE;
97	      }
98	      return sum + reimbursement - DEDUCTIBLE;
99	    },
100	    0,
101	  );
102	  return { payout };
103	}
